INSERT OR IGNORE INTO seed_runs (id, phase_id, phase_name, batch_name, environment, status, actor, source_manifest_uri, started_at, completed_at, rows_extracted, rows_inserted, rows_updated, rows_rejected, notes, created_at, updated_at) VALUES ('seed_run_s03_jurisdictions_20260421', 'S03', 'Jurisdictions and Administrative Boundaries', 'jurisdiction-and-constituency-seed', 'production', 'completed', 'replit-agent', 'docs/reports/phase-s03-jurisdiction-source-manifest-2026-04-21.md', unixepoch(), unixepoch(), 11080, 12539, 0, 0, 'Seeded source-backed administrative and electoral jurisdictions: 9,621 country/state/LGA/ward jurisdictions, 109 senatorial districts, 360 federal constituencies, and 990 state constituency rows from the official INEC workbook. The 993 public reference remains documented as a source variance until a row-level official source is available.', unixepoch(), unixepoch());

INSERT OR IGNORE INTO seed_sources (id, source_key, name, owner, source_type, confidence, url, access_method, license, publication_date, retrieved_at, source_hash, freshness_status, notes, created_at, updated_at) VALUES ('seed_source_webwaka_canonical_geography_s01_20260421', 'webwaka:canonical-geography-s01:2026-04-21', 'WebWaka Canonical Nigeria Geography Seed', 'WebWaka OS', 'internal', 'official_verified', 'infra/db/seed/0002_lgas.sql;infra/db/seed/0003_wards.sql', 'repository_sql_seed', 'internal', '2026-04-21', unixepoch(), NULL, 'current', 'S01 reconciled canonical Nigeria country, zone, state/FCT, LGA, and ward place hierarchy used to derive administrative jurisdictions.', unixepoch(), unixepoch());

INSERT OR IGNORE INTO seed_sources (id, source_key, name, owner, source_type, confidence, url, access_method, license, publication_date, retrieved_at, source_hash, freshness_status, notes, created_at, updated_at) VALUES ('seed_source_inec_constituencies_xls_201902_20260421', 'inec:constituency-delimitation-xls:2019-02:retrieved-2026-04-21', 'Name of Senatorial Districts, Federal and State Constituencies Nationwide', 'Independent National Electoral Commission (INEC)', 'official_government', 'official_stale', 'https://www.inecnigeria.org/wp-content/uploads/2019/02/Name-of-Senatorial-DistrictsFederal-and-State-Constituencies-Nationwide-1.xls', 'direct_download_xls', 'public sector publication; no explicit open-data license found on workbook', '2019-02', unixepoch(), 'a094e8cadd3f7a47986ed546a1a6d9fb3707feaa879492f43f33fa9c116d751b', 'stale', 'Official INEC workbook used as row-level constituency boundary source. Extracted counts: 109 senatorial districts, 360 federal constituencies, 990 state constituency rows. Public 2023 references to 993 state constituency seats are documented as a variance pending a newer row-level INEC boundary file.', unixepoch(), unixepoch());

INSERT OR IGNORE INTO seed_raw_artifacts (id, seed_run_id, source_id, artifact_type, file_path, content_hash, row_count, schema_json, extraction_script, status, created_at, updated_at) VALUES ('seed_artifact_s03_inec_constituencies_xls_20260421', 'seed_run_s03_jurisdictions_20260421', 'seed_source_inec_constituencies_xls_201902_20260421', 'raw', 'https://www.inecnigeria.org/wp-content/uploads/2019/02/Name-of-Senatorial-DistrictsFederal-and-State-Constituencies-Nationwide-1.xls', 'a094e8cadd3f7a47986ed546a1a6d9fb3707feaa879492f43f33fa9c116d751b', 1459, '{"workbook_sheets":["SEN. DIST.","FED. CONST.","STATE CONST."],"columns":["S/N","name","code","composition","collation_centre"],"extracted_counts":{"senatorial_districts":109,"federal_constituencies":360,"state_constituencies_source_rows":990,"state_constituencies_note":"The official INEC XLS extracted on 2026-04-21 contains 990 state constituency code rows; 993 public references require a newer row-level boundary source before seeding additional records."}}', 'xlrd extraction from official INEC XLS; constituency codes mapped to canonical state/FCT places by INEC code suffix', 'parsed', unixepoch(), unixepoch());

INSERT OR IGNORE INTO jurisdictions (id, place_id, territory_type, name, created_at, updated_at) SELECT 'jur_' || geography_type || '_' || replace(id, 'place_', ''), id, geography_type, name, unixepoch(), unixepoch() FROM places WHERE geography_type IN ('country','state','local_government_area','ward');

INSERT OR IGNORE INTO seed_entity_sources (id, seed_run_id, source_id, artifact_id, entity_type, entity_id, source_record_id, source_record_hash, confidence, source_url, extracted_at, last_verified_at, verification_state, notes, created_at, updated_at) SELECT 'seed_entity_source_s03_admin_' || j.id, 'seed_run_s03_jurisdictions_20260421', 'seed_source_webwaka_canonical_geography_s01_20260421', NULL, 'jurisdiction', j.id, j.place_id, NULL, 'official_verified', 'infra/db/seed/0002_lgas.sql;infra/db/seed/0003_wards.sql', unixepoch(), unixepoch(), 'source_verified', 'Administrative jurisdiction derived one-to-one from canonical S01 place hierarchy.', unixepoch(), unixepoch() FROM jurisdictions j WHERE j.territory_type IN ('country','state','local_government_area','ward');

